var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"할 게 생각보다 많네.","JPN":"意外とやることが多いわね。","ENG":"There's a lot more work to do than I expected.","TWN":"沒想到有那麼多要預備的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"라우라, 그쪽은 어때?","JPN":"ラウラ、そっちはどう？","ENG":"Laura, how are you doing?","TWN":"蘿拉，你那邊怎麼樣？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"바쁜 거 안 보여? 일손 부족하면 유나나 잉그리드 시켜.","JPN":"こっちも忙しい。人手が足りないならユナかイングリッドに頼め。","ENG":"Can't you see I'm busy? Make Yuna or Ingrid do it if you need an extra hand.","TWN":"沒看到我很忙嗎？人手不夠就使喚尤娜和英格麗。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"우리도 바빴거든? 웨딩 드레스를 몇 벌이나 만들었는데!","JPN":"私たちも忙しかったんだよ！　ウェディングドレスを何着作ったと思う？","ENG":"We were busy too, you know. Do you know how many wedding dresses we made?!","TWN":"我們也很忙好嗎！我們已經做好幾件婚紗咧！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L9_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"그래! 옷 만드는 게 어디 쉬운 일인 줄 알아?","JPN":"そうだよ！　ドレスを作るのって簡単じゃないんだよ！","ENG":"Yeah! Do you think making dresses is a piece of cake?","TWN":"就是說！你以為做衣服很容易嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"하아? 이제 옷 좀 만들어 봤다, 이거야?","JPN":"はあ？　何着かドレスを作ったくらいで偉そうに。","ENG":"Oh, so now you think you know your clothes, huh?","TWN":"蛤？才做幾件衣服就囂張啦？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그만큼 잘 만들었던데? 다들 고생 많았어.","JPN":"それくらいよくできていたわよ？　頑張ったわね。","ENG":"To be fair, they did a good job. Great work, everyone.","TWN":"做得很好呢？你們辛苦囉。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"거 봐!","JPN":"ほら！","ENG":"See?","TWN":"看吧！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"…뭐. 급하게 만든 작업물치고 나쁘진 않았다만.","JPN":"……まあ、急いで作った割にはよくできていたが。","ENG":"...Fine. It wasn't terrible, considering the small amount of time they had.","TWN":"……嗯哼，在短時間內做出這樣的成品，確實還不錯啦。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"자세히 뜯어보면 또 모르지. 바느질이 엉망이라 금방 뜯어질 수도 있는 거고.","JPN":"でも、細かく見ないとわからない！　縫い方が雑だからすぐに破れてしまうかもしれないしな。","ENG":"BUT! Maybe upon closer inspection, the stitching is a mess and it falls apart. You never know.","TWN":"不過細看的話就不一定囉，線縫得亂七八糟的，好像一下就會裂開的樣子。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"우으, 정말 심술 궂다니깐.","JPN":"うう、本当に意地悪なんだから。","ENG":"Ugh, you're so mean.","TWN":"嗚嗚，蘿拉嘴巴好壞。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"창고에서 드레스랑 어울릴 만한 것 좀 찾아 올게!","JPN":"倉庫からドレスに似合うようなもの探してくるね！","ENG":"I'm gonna go to the storage room and find some extra things to pair with the dress!","TWN":"我去倉庫找找有沒有適合搭配婚紗的東西。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"나도 같이 가!","JPN":"私も行くよ！","ENG":"Wait for me!","TWN":"我也一起去！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"……좀 불안한데. 또 이상한 거 주워 오는 거 아냐?","JPN":"……不安だな。また変なものを拾ってくるんじゃないのか？","ENG":"...Something feels wrong. What if they bring some weird garbage?","TWN":"……我有點不好的預感，她們該不會又撿什麼奇怪的東西回來吧？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"밖은 또 왜 이렇게 시끄러워?","JPN":"外はなんでまた騒がしいんだ？","ENG":"And why is it so noisy outside?","TWN":"外面怎麼這麼吵？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"아직 오픈 전인데. 벌써 신 메뉴 소식을 들은 건가?","JPN":"まだ、オープン前なのにね。もう新メニューの噂を聞きつけたのかしら？","ENG":"We haven't opened yet. Or did they already hear about our new menu?","TWN":"都還沒開門客人就已經收到消息，知道我們要推出新菜單嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"홍보도 제대로 안 했는데?","JPN":"宣伝もしていないのに？","ENG":"But we haven't even done any promoting.","TWN":"我們根本都還沒宣傳欸？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"무슨 일인지 한번 알아 와 봐.","JPN":"どういうことか確認してきてくれ。","ENG":"Go find out what the fuss is about.","TWN":"你去看看怎麼回事。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"알겠어~","JPN":"わかったわ～","ENG":"Roger!","TWN":"OK～"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"저기 직원이 나왔어!","JPN":"あ、店員が出てきた！","ENG":"One of the staff members is out!","TWN":"欸！有人出來咧！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"와! 마녀 복장이잖아? 웨딩 드레스는 아직인가?","JPN":"わあ～魔女の服よ。ウェディングドレスはまだなのかな？","ENG":"Oh! It's a witch costume! Where's the wedding dress?","TWN":"欸！怎麼還是魔女的裝扮？婚紗還沒好嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"음? 이게 대체 무슨 일이람?","JPN":"うん？　これはいったいどういうことなの？","ENG":"Hmm? What's going on?","TWN":"嗯？這到底是怎麼回事？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"언제 시작할까? 아직 웨딩 차원 함선은 안 보이는데?","JPN":"いつ始まるんだろう？　まだウェディング次元艦船は見えないけど？","ENG":"When will it start? I don't see the wedding-themed dimensional ship yet.","TWN":"是什麼時候開始？也沒看到婚禮次元艦船欸？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"꽃잎을 뿌리는 거대 미러볼이 공중에 떠 있다고 하지 않았어?","JPN":"花びらを撒く大きなミラーボールが空中に浮かんでるって言ってなかった？","ENG":"I heard there was gonna be a giant, floating mirror ball that sprays flower petals.","TWN":"不是說會有撒落花瓣的巨型鏡球嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"으음……? 미러볼?","JPN":"え……？　ミラーボール？","ENG":"Umm... A mirror ball...?","TWN":"嗯……？鏡球？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"웨딩 드레스는 아직 환복 전이신가 봐요.","JPN":"ウェディングドレスにまだ着替えてないんですね。","ENG":"I guess you haven't changed into your wedding dresses yet.","TWN":"看來是還沒換成婚禮主題。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"코스튬으로도 유명한 곳이라 꽤 기대하고 있답니다? 후훗.","JPN":"コスチュームでも有名なカフェだから期待しているんですが。フフッ。","ENG":"This place is famous for its costumes, so we're all very excited. Ha ha.","TWN":"這裡是以服裝出名的，所以大家都很期待呢，呵呵。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"실례지만, 혹시 웨딩 드레스 이야기는 어디서 들으셨나요?","JPN":"失礼ですが、ウェディングドレスの話はどちらでお聞きになったんですか？","ENG":"Excuse me, but where did you hear about the wedding dresses?","TWN":"請問一下，你們是從哪裡聽到婚禮主題的事的？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"차원 함선이나 미러볼 얘기는 또 무슨 이야기인지…….","JPN":"次元艦船やミラーボールとは何のお話なのか……","ENG":"And what do you mean by a dimensional ship and mirror balls...?","TWN":"還有次元艦船，和那個什麼鏡球又是什麼……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"아! 스트레가 직원 분들께서 인터뷰를 해 주셨거든요.","JPN":"あ！　ストレガの店員の方がインタビューを受けてくださったんです。","ENG":"Oh! The employees of Cafe Strega told us in the interview.","TWN":"喔！是史特雷加的員工接受採訪時說的。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"여기, 인터넷 기사를 보시면…….","JPN":"ここのインターネットの記事を見ていただければ……","ENG":"Here, read this article and you'll see...","TWN":"你看網路新聞……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"……그렇다는데?","JPN":"……って言うんだけど。","ENG":"...So, yeah.","TWN":"……就是這麼回事。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"이, 이 사고뭉치들이……!","JPN":"あ……あの問題児ども……！","ENG":"Y-you brats...!","TWN":"又是她們這二個闖禍精……！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"유나! 잉그리드! 당장 나와!","JPN":"ユナ！　イングリッド！　出てこい！","ENG":"Yuna! Ingrid! Come out here, NOW!","TWN":"尤娜！英格麗！馬上給我出來！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"응? 라우라?","JPN":"ん？　ラウラ？","ENG":"Yeah? Laura?","TWN":"嗯？蘿拉？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"왜? 아직 드레스에 어울리는 건 못 찾았는데?","JPN":"どうしたの？　まだドレスに似合うものは見つかってないんだけど？","ENG":"Why? We haven't found anything for dresses yet.","TWN":"幹嘛？還沒找到搭配婚紗的東西欸？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"대체 어쩌자고 이런 인터뷰를 한 거야!","JPN":"いったいどうしてこんなインタビュー受けたんだ！","ENG":"What were you thinking when you did this interview?!","TWN":"你們到底在想什麼，為什麼要接受採訪！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"인터뷰?","JPN":"インタビュー？","ENG":"Interview?","TWN":"採訪？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"앗! 맞다! 이런 거 했었어!","JPN":"あ！　そうだ！　私、したかも！","ENG":"Oh! Right! Yeah, we did that!","TWN":"喔，對喔！我們有接受採訪！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L12_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"뭐? 차원 함선? 불타오르는 새가 불꽃 쇼를 해?","JPN":"何だって？　次元艦船？　燃え上がる鳥がファイアーショーをするって？","ENG":"A dimensional ship? A flaming bird and a fire show?","TWN":"什麼？次元艦船？火鳥表演煙花秀？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"태양의 마도서가 네 장난감이야?!","JPN":"太陽の魔導書は汝のおもちゃか！？","ENG":"Is the grimoire of the sun a joke to you?!","TWN":"太陽法典是你的玩具嗎？！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"아쉽네. 미리 말해 줬으면 비슷하게 준비는 해 봤을 텐데.","JPN":"惜しいわね。先に言ってくれれば近い形に準備したのに。","ENG":"What a shame. If you had told us earlier, we would've tried to make something work.","TWN":"真可惜，你們早點說的話，起碼能準備個類似的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"안 해! 절대로!","JPN":"しないぞ！　絶対に！","ENG":"As if! I would never allow that!","TWN":"不行！絕對不可以！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"이상하네. 원래 결혼할 때 저 정도는 다 하지 않아?","JPN":"おかしいな。もともと結婚式ってそのくらいしない？","ENG":"Strange. Isn't that the norm for weddings?","TWN":"奇怪，婚禮不都是這麼搞的嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"맞아. 네크로노미코에도 나왔는데…….","JPN":"そうだよ。ネクロノミコにも出てたのに……","ENG":"Yeah. I saw it on Necronomiko too...","TWN":"沒錯，亡靈之書裡面也是這樣演的……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"너희는 또 그 만화 영화 타령이야? 대체 언제 철이 들래?","JPN":"またそのアニメの話か？　いったいいつになったら大人になるんだ。","ENG":"Again, with that children's cartoon. When will you grow up?","TWN":"又給我提那部動漫！你們二個究竟什麼時候才能懂事？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"흥분하지 마, 라우라.","JPN":"そう怒らないで、ラウラ。","ENG":"Calm down, Laura.","TWN":"你別激動，蘿拉。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"지금은 네크로노미코보다 가게 앞에 모여든 사람들이 먼저 아닐까?","JPN":"今はネクロノミコのことより、店の前に集まった人をどうするかでしょう？","ENG":"Necronomiko isn't the issue. We have to take care of the crowd in front of the shop first.","TWN":"現在重點不是亡靈之書，還是快想想門口那些人該怎麼辦吧？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"뭘 어떻게? 몰려든 인원이 저렇게나 많은데.","JPN":"どうしろっていうんだ？　あんなにたくさんいるのに。","ENG":"Take care of it, how? Just look at how many people are out there.","TWN":"能怎麼辦？現在外面都被擠得水泄不通。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"지금이라도 나가서 착오가 있던 거라고 말해 보는 건 어때?","JPN":"今からでも誤解だって説明したらどうかしら？","ENG":"Why don't we just tell them that this was all a big misunderstanding?","TWN":"還是現在出去大家說這是誤會一場？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"아니. 무르기엔 이미 늦었어. 이 바보들 얼굴이 기사에 대문짝만하게 실렸잖아.","JPN":"いいや。取り消すにはもう遅い。すでにこのバカどもの顔が記事にバカでかく載っているんだ。","ENG":"No. It's too late. These idiots' faces are on the front page of the article.","TWN":"不行，來不及了，這二個笨蛋的臉已經占據整個新聞版面了。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"여기서 모른 척했다간 우리 가게 평점은 끝장이야.","JPN":"ここで知らないふりをすれば、店の評判は地に落ちる。","ENG":"Our ratings will plummet if we deny anything.","TWN":"要是現在才說不知道有這回事，那咖啡廳一定會被刷一星負評。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그렇다면……","JPN":"だとすると……","ENG":"Then...","TWN":"那……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"이런 건 어떨까?","JPN":"こういうのはどう？","ENG":"How about this?","TWN":"這樣如何？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"아까 그 직원이다!","JPN":"さっきの店員さんだ！","ENG":"It's the staff from before!","TWN":"是剛才那個員工！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"휴. 걱정이네요.","JPN":"ふう……心配だわぁ～","ENG":"*Sigh.* I'm concerned.","TWN":"哀，真令人擔心。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"안에 무슨 일 있나요?","JPN":"中で何かあったんですか？","ENG":"Is something wrong?","TWN":"裡面發生什麼事嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"신부가 웨딩 슈즈를 잃어 버려서요. 저희 직원들이 열심히 찾는 중이랍니다.","JPN":"花嫁がウェディングシューズをなくしてしまったんです。私たちで必死に探しているところなのですが。","ENG":"Our bride lost her wedding shoes. The staff members are trying their best to find it.","TWN":"新娘不小心把鞋子搞丟，大家現在都忙著找鞋呢。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"저런. 이벤트에 차질이 생긴 건가요?","JPN":"あらまあ。ではイベントに支障が？","ENG":"Oh dear. Is there a problem with the event?","TWN":"怎麼這樣？那活動會受到影響嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"아! 피로연은 문제없이 진행될 거예요. 손님들이 이렇게 모였는데, 그냥 보내드릴 순 없죠.","JPN":"あ！　披露宴は問題なく行われると思います。お客さんがこれほど集まっているのに、このままお引き取りいただくわけにはいかないでしょう。","ENG":"Oh! The reception will be held without any issues. With this many customers, we could never just send you back on an empty stomach.","TWN":"放心！喜宴會正常進行，客人們都來了，當然不能讓你們敗興而歸囉。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LENI_NPC_SUPPLEMENT_GIRL","text":{"KOREA":"레니는 딸기 우유가 먹고 싶어요!","JPN":"レニーはいちご牛乳が飲みたい！","ENG":"Lenny wants strawberry milk!","TWN":"蘭妮想喝草莓牛奶！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L44_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"어머, 귀여운 꼬마 마녀네? 스트레가 온다고 마녀처럼 입고 왔구나?","JPN":"まあ、かわいいちびっ子魔女さんね！　ストレガに来るから魔女の格好で来たの？","ENG":"Oh my, you're an adorable little witch, aren't you? You must've dressed up like a witch for the cafe.","TWN":"哇喔，好可愛的小魔女喔，是特別打扮成小魔女來史特雷加嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"딸기 우유보다 더 맛있는 딸기 소다는 어때?","JPN":"いちご牛乳よりもおいしい、いちごソーダはいかが？","ENG":"How about a strawberry soda, that's tastier than strawberry milk?","TWN":"草莓汽水比草莓牛奶還好喝喔，你要喝喝看嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LENI_NPC_SUPPLEMENT_GIRL","text":{"KOREA":"좋아요!","JPN":"欲しい！","ENG":"Okay!","TWN":"要！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"후훗. 우리 꼬마 마녀에게는 특별히 딸기와 생크림 디저트도 얹어 줘야겠네~","JPN":"ふふっ。ちびっ子魔女さんには特別サービスでいちごと生クリームのデザートもあげるわね～","ENG":"Ha ha. I should give this little witch some extra strawberries and whipped cream on their drink!","TWN":"呵呵，上面還會幫你加草莓跟鮮奶油喔～"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"아! 웨딩 슈즈, 찾았나 본데요?","JPN":"あ！　ウェディングシューズが見つかったようです。","ENG":"Oh! Sounds like they found the wedding shoes.","TWN":"喔！找到鞋子啦？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그럼 어디…….","JPN":"それでは……","ENG":"Let's see...","TWN":"那麼現在……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"무, 문을 열었는데 숲이 나왔어?!","JPN":"と、扉を開けたら森が！？","ENG":"W-what?! The cafe door led to a forest?!","TWN":"門，門後竟然是一片森林？！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"진짜 마법 같아! 어떻게 만든 거지?!","JPN":"本当に魔法みたい！　どうやって作ったのかな！？","ENG":"It's as if they used real witchcraft! How did they pull this off?!","TWN":"真的好像魔法喔！這是怎麼辦到的？！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"쉿! 저기 누가 있어!","JPN":"シッ！　あそこに誰かいる！","ENG":"Shhh! There's someone over there!","TWN":"噓！那邊好像有人！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LENI_NPC_SUPPLEMENT_GIRL","text":{"KOREA":"와아…….","JPN":"わあ……","ENG":"Whoa...","TWN":"哇……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LENI_NPC_SUPPLEMENT_GIRL","text":{"KOREA":"공주님이다!","JPN":"お姫様だ！","ENG":"She's a princess!","TWN":"是公主欸！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"공주 아니고 마녀거든? 애가 보는 눈이 없네.","JPN":"お姫様じゃなくて魔女だ。この子は見る目がないな。","ENG":"I'm a witch, not a princess! That kid needs glasses.","TWN":"才不是公主，是魔女！小朋友亂說話。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LENI_NPC_SUPPLEMENT_GIRL","text":{"KOREA":"흐잉…….","JPN":"ふえん……","ENG":"Hng...","TWN":"嗚嗚……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"에블린. 이게 계획이야?","JPN":"エヴリン。これが計画とやらなのか？","ENG":"Evelyn, this is your big plan?","TWN":"伊芙琳，這就是你的計畫？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"내가 이 웨딩 드레스를 입는 게?","JPN":"妾がウェディングドレスを着るのが？","ENG":"For me to wear this wedding dress?","TWN":"讓我穿上這件婚紗？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"왜~? 마음에 안 들어? 잘 어울리는데.","JPN":"なに～？　気に入らないの？　よく似合ってるわよ。","ENG":"Whaaat? You don't like it? I think it looks good on you.","TWN":"怎麼啦～？你不喜歡嗎？很適合你呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"잘 어울리는 게 문제가 아니라 왜 하필 나냐구!","JPN":"似合うかどうかが問題じゃなくて、なぜ妾なんだ！","ENG":"That's not the issue here! Why me?!","TWN":"不是適不適合的問題，為什麼偏偏是我！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"유나도 있고, 잉그리드도 있잖아? 아니면 플루토라도 입히던가!","JPN":"ユナもイングリッドもいるじゃないか。プルートーに着せるとか！","ENG":"Why not Yuna or Ingrid? Or even Pluto!","TWN":"不是還有尤娜和英格麗？再不然讓布魯托穿也可以吧！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"플루토… 도 괜찮았겠네. 그러게.","JPN":"プルートー……でも良かったわね。確かに。","ENG":"Come to think of it... Pluto would've been a good option.","TWN":"布魯托……好像也可以，對欸。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"장난치지 말고!","JPN":"ふざけてないで！","ENG":"Stop joking around!","TWN":"你不要跟我嘻嘻哈哈的！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"저 바보 둘이 후닥닥 만든 드레스를 불안해서 어떻게 입고 있으란 거야?","JPN":"あのバカ二人が即席で作ったドレスなど不安で着ていられるか！","ENG":"How do you expect me to keep wearing something that those two dummies made in a rush!","TWN":"那兩個笨蛋匆匆忙忙做出來的婚紗，是要我怎麼穿啦？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"조금만 움직여도 갑자기 옷이 뜯어지거나 할 것 같다고.","JPN":"ちょっと動いただけで破れそうな気がするんだ！","ENG":"I'm worried it's going to tear if I try so much as to turn my head.","TWN":"我現在好像只要隨便動一下，衣服就會裂開！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"할로윈 때 못 봤어?","JPN":"ハロウィンのとき見たでしょう？","ENG":"You saw what they did on Halloween.","TWN":"萬聖節的時候你沒看到嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"물론 잉그리드나 유나가 아직 마법 실력은 부족하지만, 옷 만드는 솜씨만큼은 인정해 줘야지.","JPN":"もちろん、イングリッドやユナは魔法の実力はまだまだだけど、服を作る腕は認めてあげないと。","ENG":"They might not be the best at magic, but they do one heck of a job making costumes.","TWN":"雖然英格麗和尤娜的魔法能力還有待加強，但你必須承認她們做的衣服還蠻不錯的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"흠흠. 신경 좀 썼다구.","JPN":"おっほん！　頑張ったんだから！","ENG":"Ahem. I put a lot of effort into it, you know.","TWN":"對嘛，我們很用心欸！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"이렇게 오냐오냐 키우니까 애들이 버릇없어지지.","JPN":"こうして甘やかすからあいつらがつけあがるんだ。","ENG":"No wonder they're so spoiled. You coddle them too much.","TWN":"你老是這樣替她們說話，她們才會恃寵而驕。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그럼 다른 드레스는 어때?","JPN":"だったら、他のドレスはどう？","ENG":"What about a different dress then?","TWN":"那不然還是你試試其他婚紗？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"……장난해? 애초에 나랑 맞는 사이즈가 지금 입은 거 말곤 없거든?","JPN":"……ふざけてるのか？　そもそも妾に合うサイズはこれしかないぞ！","ENG":"...Are you kidding me? The one I'm wearing right now is the only dress that fits.","TWN":"……你在拿我開玩笑嗎？就只有我身上穿的這件尺寸是適合我的！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"계획이 뭐든 이렇게는 더 못하니까, 지금이라도 나가서 사실대로 말하고…….","JPN":"計画がどうであれ、この格好は御免だ。今からでも出ていって事実を……","ENG":"Whatever your plan is, this can't go on. Let's go out now and tell them the truth...","TWN":"不管你的計畫是什麼，這樣我沒辦法，我要出去跟大家說實話……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"이제 시작하려나?","JPN":"そろそろ始まるのかな？","ENG":"Are they about to begin?","TWN":"現在要開始了嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"컨셉이 심상치 않네. 어떤 내용일까?","JPN":"コンセプトが普通じゃないもの。どんな内容なのかしら？","ENG":"It's an interesting theme. I wonder what it's going to be about.","TWN":"主題很特別欸，不知道是什麼內容？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"후후. 그러게요. 꽤 재밌는 연극이 될 것 같아요.","JPN":"ふふ。そうですね。かなりおもしろい演劇になると思いますよ。","ENG":"Ha ha. I'm curious too. It's going to be an amusing play.","TWN":"呵呵，是呀，感覺會是一齣很有趣的戲。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>마녀의 피로연</color>이라, 헤드라인도 좋고요.","JPN":"<color=#ffd34c>魔女の披露宴</color>というタイトルもいいですしね。","ENG":"<color=#ffd34c>Witch's Wedding</color>, it'll make an attention-grabbing headline.","TWN":"<color=#ffd34c>魔女的喜宴</color>，這個標題也很不錯。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"정말? 사실대로 말할 거야? 반응이 나쁘지 않은데?","JPN":"本当に？　事情を説明するって？　反応は悪くないのに。","ENG":"Are you sure? You want to come clean when people are showing interest?","TWN":"真的嗎？你確定要說實話嗎？目前反應還不錯呢？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"하아… 그래. 마음대로 해 봐. 어울려 줄 테니까.","JPN":"はあ……わかったよ。やりたいようにやってみろ。合わせるから。","ENG":"*Sigh...* Fine. Whatever. I'll play along.","TWN":"哀哀……隨便吧，大家開心就好，我配合大家。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"후훗.","JPN":"ふふっ。","ENG":"Ha ha.","TWN":"呵呵。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"우리 꼬마 마녀님. 잠깐 여기로 와 볼래?","JPN":"ちびっ子魔女さん。ちょっとこっちに来てくれる？","ENG":"Hey, little witch. Wanna come here for a sec?","TWN":"小魔女，你可以過來一下嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LENI_NPC_SUPPLEMENT_GIRL","text":{"KOREA":"왜요?","JPN":"なあに？","ENG":"Why?","TWN":"要做什麼？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"우리 마녀들이 해야 할 게 따로 있단다.","JPN":"私たち魔女はやることがあるの。","ENG":"We witches have a job to do.","TWN":"因為我們這些魔女有些任務。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"공주가 무사히 피로연을 열 수 있도록 손님들이랑 함께 힘을 모아야 해.","JPN":"お姫様が無事に披露宴を挙げられるように、お客さんと力を合わせないといけないの。","ENG":"We have to work together with the customers so that the princess's wedding reception can happen without a hitch.","TWN":"就是我們要和客人團結起來，幫助公主可以順利舉辦喜宴。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"곧 <color=#ffd34c>어둠의 신부</color>가 나타날 거거든!","JPN":"もうすぐ<color=#ffd34c>闇の花嫁</color>が現れるからね！","ENG":"Because soon the <color=#ffd34c>bride of darkness</color> will appear!","TWN":"因為<color=#ffd34c>壞新娘</color>很快就會登場囉！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LENI_NPC_SUPPLEMENT_GIRL","text":{"KOREA":"어, 어둠의 신부요?","JPN":"や、闇の花嫁？","ENG":"B-bride of darkness?","TWN":"壞，壞新娘？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그래. 오늘 피로연을 방해하러 온댔어. 우린 그걸 막을 마녀들이고.","JPN":"そう。今日の披露宴を邪魔しに来るらしいの。私たちはそれを防ぐ魔女なのよ。","ENG":"Yes. She's going to interfere with the reception. We're the witches that have to put a stop to it.","TWN":"是呀，她是來妨礙喜宴的，所以我們要阻止她！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LAURA_STREGA_WEDDING_NULL","text":{"KOREA":"그건 또 무슨 컨셉이야……?","JPN":"それはどういうコンセプトなんだ……？","ENG":"What's that about...?","TWN":"這又是在演哪一齣……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"뭐든 순탄하면 재미없잖아? 후훗.","JPN":"なんでも順調だとおもしろくないでしょ？　ふふっ。","ENG":"There are always obstacles to a good story, ha ha.","TWN":"都很順利的話不是很無聊嗎？呵呵。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"에블린, 준비 다 됐어!","JPN":"エヴリン、準備できたよ！","ENG":"Evelyn, we're ready!","TWN":"伊芙琳，都準備好囉！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP"},{"id":"L10_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그래? 그럼 시작해 볼까?","JPN":"そう？　じゃあ、始めましょうか？","ENG":"Well, shall we begin?","TWN":"是嗎？那我們就開始吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"뭐, 뭐야! 조명 나갔나?","JPN":"なっ、何だ！　照明が消えた？","ENG":"W-what? The lights are out!","TWN":"怎，怎麼回事！燈壞啦？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"뭔가 시작되려나 봐!","JPN":"始まるみたいよ！","ENG":"Something's about to start!","TWN":"好像有什麼動靜！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};